UPDATE TBL_ROADMAP
SET ROADMAP_IMAGE_PATH = #{roadmapImagePath}
WHERE JOB_NUMBER = #{jobNumber}

UPDATE TBL_ROADMAP_JOB
SET
	ROADMAP_JOB_NAME = #{roadmapJobName},
	ROADMAP_JOB_DESC = #{roadmapJobDesc}
WHERE ROADMAP_JOB_NUMBER = #{roadmapJobNumber}

UPDATE TBL_ROADMAP_CURRICULUM
SET
	SKILL_TYPE = #{skillType},
	SKILL_NAME = #{skillName},
	SKILL_DESC = #{skillDesc}
WHERE CURRICULUM_NUMBER = #{curriculumNumber}

UPDATE TBL_ROADMAP_REC
SET
	REC_TYPE = #{recType},
	REC_NAME = #{recName}
WHERE REC_NUMBER = #{recNumber}
